//! Image generation via Gemini's native multimodal output.
//! Uses `responseModalities: ["TEXT", "IMAGE"]` — the model returns both
//! a text description and a base64-encoded PNG inline.
//!
//! We discard the text and extract only the image data.

use base64::Engine;
use rand::Rng;
use serde_json::{json, Value};

use super::{ConnectionDto, ProviderError};

fn api_err(status: u16, msg: impl Into<String>) -> ProviderError {
    ProviderError::Api {
        status,
        message: msg.into(),
    }
}

/// Calls Gemini and returns the generated image as raw PNG bytes.
pub async fn generate_image(
    connection: &ConnectionDto,
    api_key: &str,
    prompt: &str,
) -> Result<Vec<u8>, ProviderError> {
    let client = reqwest::Client::new();
    let url = format!(
        "https://generativelanguage.googleapis.com/v1beta/models/{}:generateContent",
        connection.model
    );

    let body = json!({
        "contents": [{
            "parts": [{ "text": prompt }]
        }],
        "generationConfig": {
            "responseModalities": ["TEXT", "IMAGE"],
            "imageConfig": {
                "aspectRatio": "1:1",
                "imageSize": "1K"
            }
        }
    });

    let res = client
        .post(&url)
        .header("x-goog-api-key", api_key)
        .json(&body)
        .send()
        .await?;

    let status = res.status();
    let text = res.text().await?;

    if !status.is_success() {
        return Err(api_err(status.as_u16(), text));
    }

    let v: Value = serde_json::from_str(&text).map_err(|e| api_err(200, format!("Invalid JSON: {e}")))?;
    let parts = v["candidates"][0]["content"]["parts"]
        .as_array()
        .ok_or_else(|| api_err(200, "No parts in Gemini image response"))?;

    for part in parts {
        if let Some(inline) = part["inlineData"].as_object() {
            if inline.get("mimeType").and_then(|m| m.as_str()) == Some("image/png") {
                if let Some(b64) = inline.get("data").and_then(|d| d.as_str()) {
                    return base64::engine::general_purpose::STANDARD
                        .decode(b64)
                        .map_err(|e| api_err(200, format!("Failed to decode base64 image: {e}")));
                }
            }
        }
    }

    Err(api_err(200, "No image data found in Gemini response"))
}

/// Free image generation via pollinations.ai — no API key needed.
/// Wraps Stable Diffusion behind a simple GET endpoint.
/// Falls back when Gemini is geo-blocked.
pub async fn generate_image_free(prompt: &str) -> Result<Vec<u8>, ProviderError> {
    let client = reqwest::Client::new();
    let seed: u64 = rand::thread_rng().gen();
    let styles = [
        "oil painting, dramatic lighting",
        "digital fantasy art, vibrant colors",
        "dark fantasy, moody atmosphere",
        "watercolor illustration, soft tones",
        "realistic portrait, detailed features",
        "comic book style, bold lines",
        "pencil sketch, rough shading",
        "anime art style, clean lines",
        "gothic illustration, ornate details",
        "minimalist vector art, flat colors",
    ];
    let style = styles[rand::thread_rng().gen_range(0..styles.len())];
    let unique_prompt = format!("{prompt}, {style} [seed:{seed}]");
    let url = format!(
        "https://image.pollinations.ai/prompt/{}?width=512&height=512&nologo=true",
        urlencoding(&unique_prompt)
    );

    let res = client.get(&url).send().await?;
    let status = res.status();
    if !status.is_success() {
        return Err(api_err(status.as_u16(), "Pollinations.ai request failed"));
    }
    res.bytes().await.map(|b| b.to_vec()).map_err(|e| api_err(500, format!("Failed to read image: {e}")))
}

fn urlencoding(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for b in s.bytes() {
        match b {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => out.push(b as char),
            b' ' => out.push_str("%20"),
            _ => out.push_str(&format!("%{:02X}", b)),
        }
    }
    out
}

/**
 * In-memory FIFO background queue for auto-generating illustrations.
 *
 * One image is generated at a time (no parallelism — respects API rate
 * limits). Settings are re-read before each item so runtime changes take
 * effect without restart.
 *
 * The queue is ephemeral — items do not survive a page reload. Missing
 * images can be regenerated by locking the fact again or re-saving the
 * inventory item.
 */

import { invoke } from "@tauri-apps/api/core";
import { getSetting } from "../db/repositories/settingsRepo";
import {
  getConnection,
  listConnections,
} from "../db/repositories/connectionsRepo";
import { setFactImage } from "../db/repositories/ledgerRepo";
import { setInventoryItemImage } from "../db/repositories/personasRepo";
import { toConnectionDto } from "../providers/dto";
import type { ConnectionConfig } from "../providers/types";

// ---- queue ----------------------------------------------------------------

interface QueueItem {
  type: "fact" | "inventory";
  /** fact.id or persona.id */
  targetId: string;
  prompt: string;
  /** Only for inventory items — which item within the persona's inventory. */
  itemName?: string;
}

const queue: QueueItem[] = [];
let processing = false;
let timerId: ReturnType<typeof setTimeout> | null = null;

// ---- daily rate limiting --------------------------------------------------

let dailyCount = 0;
let lastDate = "";

function getToday(): string {
  return new Date().toISOString().slice(0, 10);
}

function resetDailyIfNeeded(): void {
  const today = getToday();
  if (today !== lastDate) {
    dailyCount = 0;
    lastDate = today;
  }
}

// ---- connection resolution ------------------------------------------------

async function resolveConnection(): Promise<ConnectionConfig | null> {
  const connId = await getSetting("image_gen_connection_id");
  if (connId) {
    return getConnection(connId);
  }
  // Fall back to the first connection that lists "image" in its purposes.
  const all = await listConnections();
  return all.find((c) => c.purposes.includes("image")) ?? null;
}

// ---- main loop ------------------------------------------------------------

async function processQueue(): Promise<void> {
  if (processing) return;
  processing = true;

  try {
    while (queue.length > 0) {
      resetDailyIfNeeded();

      // --- enabled? ---
      const enabled = await getSetting("image_gen_enabled");
      if (enabled !== "1") {
        queue.length = 0; // disabled → drain the queue silently
        break;
      }

      // --- daily limit ---
      const limitRaw = await getSetting("image_gen_limit");
      const limit = limitRaw ? parseInt(limitRaw, 10) : 0;
      if (limit > 0 && dailyCount >= limit) {
        // Stop processing but leave items in the queue — they'll be
        // picked up tomorrow when the date changes and enqueueIllustration
        // is called again.
        break;
      }

      // --- connection ---
      const connection = await resolveConnection();
      if (!connection) {
        console.warn("imageGenQueue: no connection available for image generation");
        queue.length = 0;
        break;
      }

      const item = queue.shift()!;

      try {
        const imagePath: string = await invoke("generate_illustration", {
          connection: toConnectionDto(connection),
          prompt: item.prompt,
        });

        dailyCount++;

        // Persist the result.
        if (item.type === "fact") {
          await setFactImage(item.targetId, imagePath);
        } else if (item.itemName) {
          await setInventoryItemImage(item.targetId, item.itemName, imagePath);
        }
      } catch (err) {
        console.warn("imageGenQueue: generation failed for", item.type, item.targetId, err);
        // Continue to the next item — don't let one failure stall the queue.
      }
    }
  } finally {
    processing = false;
  }
}

function scheduleProcess(): void {
  // Small delay so items enqueued in the same tick are batched into one
  // processing session, and the caller never blocks on the queue.
  if (timerId !== null) return;
  timerId = setTimeout(() => {
    timerId = null;
    void processQueue();
  }, 300);
}

// ---- public API -----------------------------------------------------------

/**
 * Enqueue an illustration request.
 *
 * @param type      `"fact"` for a ledger fact, `"inventory"` for a persona inventory item.
 * @param targetId  `fact.id` or `persona.id`.
 * @param prompt    The image-generation prompt.
 * @param itemName  Required for `"inventory"` — the `item` field of the inventory entry.
 */
export function enqueueIllustration(
  type: "fact" | "inventory",
  targetId: string,
  prompt: string,
  itemName?: string,
): void {
  // Don't queue duplicates (same type + target + item).
  if (
    queue.some(
      (i) =>
        i.type === type &&
        i.targetId === targetId &&
        (type !== "inventory" || i.itemName === itemName),
    )
  ) {
    return;
  }

  queue.push({ type, targetId, prompt, itemName });
  scheduleProcess();
}

use std::fs;
use std::io::Cursor;
use std::path::PathBuf;

use tauri::{AppHandle, Manager};

use crate::commands::secrets::get_api_key;
use crate::providers::{self, ConnectionDto};

/// Generates an illustration via Gemini, resizes it to max 512px,
/// and saves it as a PNG in the avatars directory.
/// Returns the absolute filesystem path of the saved file.
#[tauri::command]
pub async fn generate_illustration(
    app: AppHandle,
    connection: ConnectionDto,
    prompt: String,
) -> Result<String, String> {
    let api_key = get_api_key(&connection.id)
        .map_err(|e| e.to_string())?
        .ok_or_else(|| "Pro toto připojení není uložen žádný API klíč.".to_string())?;

    // Try Gemini first, fall back to free Pollinations.ai if geo-blocked
    let image_bytes = match providers::image_gen::generate_image(&connection, &api_key, &prompt).await {
        Ok(bytes) => bytes,
        Err(e) => {
            let msg = e.to_string();
            if msg.contains("not available in your country") || msg.contains("FAILED_PRECONDITION") {
                providers::image_gen::generate_image_free(&prompt).await.map_err(|e| e.to_string())?
            } else {
                return Err(msg);
            }
        }
    };

    // Resize to max 512px on the longer side — icons and avatars don't
    // need more, and smaller files load faster in the UI.
    let resized = resize_max(&image_bytes, 512)
        .map_err(|e| format!("nepodařilo se zmenšit obrázek: {e}"))?;

    let dir = avatars_dir(&app)?;
    let filename = format!("illustration_{}.png", uuid::Uuid::new_v4());
    let dest = dir.join(&filename);
    fs::write(&dest, &resized)
        .map_err(|e| format!("nepodařilo se uložit obrázek: {e}"))?;

    Ok(dest.to_string_lossy().to_string())
}

/// Resizes a PNG to at most `max_dim` pixels on the longer side,
/// keeping the aspect ratio. Returns the resized PNG bytes.
fn resize_max(png_bytes: &[u8], max_dim: u32) -> Result<Vec<u8>, String> {
    let img = image::load_from_memory(png_bytes)
        .map_err(|e| format!("nepodařilo se načíst obrázek: {e}"))?;

    let (w, h) = (img.width(), img.height());
    if w <= max_dim && h <= max_dim {
        // Already small enough — re-encode as PNG anyway to strip
        // any extra chunks the API might include.
        let mut buf = Cursor::new(Vec::new());
        img.write_to(&mut buf, image::ImageFormat::Png)
            .map_err(|e| format!("nepodařilo se uložit obrázek: {e}"))?;
        return Ok(buf.into_inner());
    }

    let ratio = if w > h {
        max_dim as f64 / w as f64
    } else {
        max_dim as f64 / h as f64
    };
    let new_w = (w as f64 * ratio) as u32;
    let new_h = (h as f64 * ratio) as u32;

    let resized = img.resize_exact(new_w, new_h, image::imageops::FilterType::Lanczos3);
    let mut buf = Cursor::new(Vec::new());
    resized
        .write_to(&mut buf, image::ImageFormat::Png)
        .map_err(|e| format!("nepodařilo se uložit obrázek: {e}"))?;
    Ok(buf.into_inner())
}

fn avatars_dir(app: &AppHandle) -> Result<PathBuf, String> {
    let base = app
        .path()
        .app_data_dir()
        .map_err(|e| format!("nepodařilo se najít adresář aplikace: {e}"))?;
    let dir = base.join("avatars");
    fs::create_dir_all(&dir).map_err(|e| format!("nepodařilo se vytvořit adresář avatarů: {e}"))?;
    Ok(dir)
}

import { convertFileSrc } from "@tauri-apps/api/core";

/** Converts an absolute filesystem avatar path (as stored in
 * `characters.avatar_path`) into a URL the webview can load as an <img>
 * src. Returns undefined when there's no avatar, so callers can fall back
 * to a placeholder.
 *
 * Appends a cache-busting query parameter so the webview always reloads
 * the image when the path changes (on-disk replacement via overwrite, or
 * when a new file gets the same logical URL through the asset protocol). */
export function avatarSrc(path: string | null): string | undefined {
  if (!path) return undefined;
  return `${convertFileSrc(path)}?t=${Date.now()}`;
}

